type Shape =
  | { kind: 'circle';    radius: number }
  | { kind: 'rectangle'; width: number; height: number }
  | { kind: 'triangle';  base: number;  height: number };

function area(shape: Shape): number {
  switch (shape.kind) {
    case 'circle':
      // shape: { kind: 'circle'; radius: number }
      return Math.PI * shape.radius ** 2;
    case 'rectangle':
      return shape.width * shape.height;
    case 'triangle':
      return 0.5 * shape.base * shape.height;
  }
}

const c: Shape = { kind: 'circle', radius: 5 };
console.log(area(c).toFixed(2)); // '78.54'

// CORRECT — string literal discriminants
type Action =
  | { type: 'INCREMENT'; amount: number }
  | { type: 'DECREMENT'; amount: number }
  | { type: 'RESET' };

// CORRECT — numeric literal discriminants
type HttpStatus =
  | { code: 200; data: unknown }
  | { code: 400; errors: string[] }
  | { code: 401 }
  | { code: 500; message: string };

// NOT a discriminated union — no shared property
type Bad1 =
  | { name: string }   // has 'name'
  | { age: number };   // no 'name'

// NOT a discriminated union — discriminant is a non-literal type (string, not 'a' | 'b')
type Bad2 =
  | { kind: string; x: number }  // string — too wide
  | { kind: string; y: number };

function assertNever(x: never): never {
  throw new Error(`Unhandled variant: ${JSON.stringify(x)}`);
}

type Action =
  | { type: 'INCREMENT'; amount: number }
  | { type: 'DECREMENT'; amount: number }
  | { type: 'RESET' };

function reduce(state: number, action: Action): number {
  switch (action.type) {
    case 'INCREMENT': return state + action.amount;
    case 'DECREMENT': return state - action.amount;
    case 'RESET':     return 0;
    default:          return assertNever(action);
    // If a new action type is added to the union without adding a case here,
    // TypeScript will error: Argument of type 'NewAction' is not assignable to type 'never'.
  }
}

// Exhaustiveness in if-else chains
function describe(action: Action): string {
  if (action.type === 'INCREMENT') return `+${action.amount}`;
  if (action.type === 'DECREMENT') return `-${action.amount}`;
  if (action.type === 'RESET')     return 'reset';
  return assertNever(action); // narrowed to never — safe exhaustion
}

import { signal, computed } from '@angular/core';
import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';

interface User { id: number; name: string }

type LoadState<T> =
  | { status: 'idle' }
  | { status: 'loading' }
  | { status: 'loaded'; data: T }
  | { status: 'error';  message: string };

@Injectable({ providedIn: 'root' })
class UserService {
  private readonly state = signal<LoadState<User[]>>({ status: 'idle' });

  readonly users  = computed(() => {
    const s = this.state();
    return s.status === 'loaded' ? s.data : [];
    // s.data only accessible after discriminant check on status
  });

  readonly error  = computed(() => {
    const s = this.state();
    return s.status === 'error' ? s.message : null;
  });

  readonly loading = computed(() => this.state().status === 'loading');

  constructor(private http: HttpClient) {}

  load(): void {
    this.state.set({ status: 'loading' });
    this.http.get<User[]>('/api/users').subscribe({
      next: data   => this.state.set({ status: 'loaded', data }),
      error: err   => this.state.set({ status: 'error', message: err.message }),
    });
  }
}

type ApiResult<T> =
  | { ok: true;  data: T;     status: 200 }
  | { ok: false; error: string; status: 400 | 401 | 404 | 500 };

function handleResult<T>(result: ApiResult<T>): T {
  if (result.ok) {
    // result: { ok: true; data: T; status: 200 }
    return result.data;
  }
  // result: { ok: false; error: string; status: 400|401|404|500 }
  switch (result.status) {
    case 401: throw new Error('Unauthorised — please log in');
    case 404: throw new Error('Resource not found');
    default:  throw new Error(`API error: ${result.error}`);
  }
}

