// Modelling Angular Router events as a discriminated union
import { Router, NavigationStart, NavigationEnd, NavigationError } from '@angular/router';
import { filter, map } from 'rxjs/operators';

type NavEvent =
  | { type: 'start'; url: string }
  | { type: 'end';   url: string }
  | { type: 'error'; url: string; error: unknown };

function toNavEvent(event: unknown): NavEvent | null {
  if (event instanceof NavigationStart) return { type: 'start', url: event.url };
  if (event instanceof NavigationEnd)   return { type: 'end',   url: event.url };
  if (event instanceof NavigationError) return { type: 'error', url: event.url, error: event.error };
  return null;
}

// Narrow at the subscriber
function handleNavEvent(ev: NavEvent): void {
  switch (ev.type) {
    case 'start': console.log('Navigating to', ev.url); break;
    case 'end':   console.log('Arrived at',   ev.url); break;
    case 'error': console.error('Nav error on', ev.url, ev.error); break;
  }
}

