type Color = 'red' | 'green' | 'blue';

function toHex(color: Color): string {
  switch (color) {
    case 'red':   return '#ff0000';
    case 'green': return '#00ff00';
    case 'blue':  return '#0000ff';
    // No default — TypeScript infers that all cases are covered
    // because Color is a closed union.
  }
  // TypeScript knows this line is unreachable — no error,
  // but the function return type is inferred as string | undefined
  // unless you enable strictNullChecks + noImplicitReturns
}

// Enable assertNever to make the gap visible:
function toHexExhaustive(color: Color): string {
  switch (color) {
    case 'red':   return '#ff0000';
    case 'green': return '#00ff00';
    case 'blue':  return '#0000ff';
    default:      return assertNever(color as never);
  }
}

function assertNever(x: never): never {
  throw new Error(`Unhandled: ${x}`);
}

// Nested discriminated union — two levels of discrimination
type HttpEvent<T> =
  | { phase: 'request' }
  | { phase: 'response'; ok: true;  body: T;      status: 200 }
  | { phase: 'response'; ok: false; error: string; status: 400 | 401 | 500 };

function handle<T>(event: HttpEvent<T>): string {
  if (event.phase === 'request') {
    return 'Sending…';
  }
  // event: { phase: 'response'; ok: true|false; … }
  if (event.ok) {
    // event: { phase: 'response'; ok: true; body: T; status: 200 }
    return `Success: ${JSON.stringify(event.body)}`;
  }
  // event: { phase: 'response'; ok: false; error: string; status: 400|401|500 }
  return `Error ${event.status}: ${event.error}`;
}

// Multi-discriminant — narrow by two literal properties together
type Notification =
  | { channel: 'email'; priority: 'high';   to: string; subject: string }
  | { channel: 'email'; priority: 'low';    to: string }
  | { channel: 'sms';   priority: 'high';   phone: string; message: string }
  | { channel: 'push';  priority: 'normal'; deviceId: string; title: string };

function dispatch(n: Notification): void {
  if (n.channel === 'email' && n.priority === 'high') {
    // n: { channel: 'email'; priority: 'high'; to: string; subject: string }
    sendUrgentEmail(n.to, n.subject);
  }
  // … other branches
}

function sendUrgentEmail(to: string, subject: string): void {}

// Order state machine — each state has exactly the properties relevant to it
type OrderState =
  | { state: 'draft';    items: string[] }
  | { state: 'placed';   items: string[]; orderId: string;  placedAt: Date }
  | { state: 'shipped';  items: string[]; orderId: string;  trackingId: string }
  | { state: 'delivered';items: string[]; orderId: string;  deliveredAt: Date }
  | { state: 'cancelled';items: string[]; orderId?: string; reason: string };

// Transition functions — each returns the next state
function placeOrder(draft: Extract<OrderState, { state: 'draft' }>): Extract<OrderState, { state: 'placed' }> {
  return {
    state: 'placed',
    items: draft.items,
    orderId: crypto.randomUUID(),
    placedAt: new Date(),
  };
}

function shipOrder(placed: Extract<OrderState, { state: 'placed' }>, trackingId: string): Extract<OrderState, { state: 'shipped' }> {
  return { state: 'shipped', items: placed.items, orderId: placed.orderId, trackingId };
}

// Type-safe state query
function getTrackingId(order: OrderState): string | null {
  if (order.state === 'shipped') return order.trackingId;
  return null; // other states do not have trackingId
}

// Display helper using exhaustive switch
function getStatusLabel(order: OrderState): string {
  switch (order.state) {
    case 'draft':     return 'Draft';
    case 'placed':    return 'Order Placed';
    case 'shipped':   return `Shipped (${order.trackingId})`;
    case 'delivered': return 'Delivered';
    case 'cancelled': return `Cancelled: ${order.reason}`;
  }
}

type LoadState<T> =
  | { status: 'idle' }
  | { status: 'loading' }
  | { status: 'loaded'; data: T }
  | { status: 'error'; message: string };

// Extract a single variant by its discriminant
type LoadedState<T> = Extract<LoadState<T>, { status: 'loaded' }>;
// { status: 'loaded'; data: T }

type ErrorState = Extract<LoadState<never>, { status: 'error' }>;
// { status: 'error'; message: string }

// Exclude one or more variants
type NonIdle<T> = Exclude<LoadState<T>, { status: 'idle' }>;
// | { status: 'loading' }
// | { status: 'loaded'; data: T }
// | { status: 'error'; message: string }

// Practical use: component input can only receive terminal states
type TerminalState<T> = Extract<LoadState<T>, { status: 'loaded' | 'error' }>;

function renderResult<T>(state: TerminalState<T>): string {
  if (state.status === 'loaded') return JSON.stringify(state.data);
  return `Error: ${state.message}`;
  // no idle or loading case — those are excluded from the type
}

// Test each variant independently — no shared mutable state needed
type Notification =
  | { kind: 'info';    message: string }
  | { kind: 'warning'; message: string; code: string }
  | { kind: 'error';   message: string; code: string; retry: boolean };

function format(n: Notification): string {
  switch (n.kind) {
    case 'info':    return `ℹ️ ${n.message}`;
    case 'warning': return `⚠️ [${n.code}] ${n.message}`;
    case 'error':   return `❌ [${n.code}] ${n.message}${n.retry ? ' — retrying' : ''}`;
  }
}

// Jest / Jasmine tests — one per variant
describe('format notification', () => {
  it('formats info', () => {
    expect(format({ kind: 'info', message: 'Saved' })).toBe('ℹ️ Saved');
  });

  it('formats warning with code', () => {
    expect(format({ kind: 'warning', message: 'Slow', code: 'W001' }))
      .toBe('⚠️ [W001] Slow');
  });

  it('formats error with retry', () => {
    expect(format({ kind: 'error', message: 'Fail', code: 'E500', retry: true }))
      .toBe('❌ [E500] Fail — retrying');
  });

  it('formats error without retry', () => {
    expect(format({ kind: 'error', message: 'Fail', code: 'E500', retry: false }))
      .toBe('❌ [E500] Fail');
  });
});

